/**
 * tarot-create-reading
 *
 * Persists a completed tarot reading session generated by the frontend.
 * The client sends the fully-generated session payload; this function
 * validates it, writes it to Supabase, persists card results and product
 * recommendations, then returns the confirmed session record.
 *
 * POST /.netlify/functions/tarot-create-reading
 * Body: {
 *   session: ReadingSession,         // client-generated reading
 *   recommendations?: RecommendedOffer[]  // optional pre-scored offers
 * }
 */

import { createClient } from "@supabase/supabase-js";

const supabase = createClient(
  process.env.SUPABASE_URL,
  process.env.SUPABASE_SERVICE_ROLE_KEY
);

export async function handler(event) {
  if (event.httpMethod !== "POST") {
    return {
      statusCode: 405,
      body: JSON.stringify({ error: "Method not allowed" }),
    };
  }

  let body;
  try {
    body = JSON.parse(event.body || "{}");
  } catch {
    return { statusCode: 400, body: JSON.stringify({ error: "Invalid JSON" }) };
  }

  const { session, recommendations = [] } = body;

  if (!session || !session.id || !session.firstName || !session.dateOfBirth) {
    return {
      statusCode: 400,
      body: JSON.stringify({ error: "Missing required session fields" }),
    };
  }

  if (!Array.isArray(session.cards) || session.cards.length === 0) {
    return {
      statusCode: 400,
      body: JSON.stringify({ error: "Session must include card results" }),
    };
  }

  try {
    // Upsert session (idempotent — safe to retry)
    const { error: sessionErr } = await supabase
      .from("reading_sessions")
      .upsert(
        {
          id: session.id,
          first_name: session.firstName,
          date_of_birth: session.dateOfBirth,
          zodiac_sign: session.zodiacSign,
          zodiac_symbol: session.zodiacSymbol ?? null,
          zodiac_element: session.zodiacElement ?? null,
          spread_type: session.spreadType ?? "three-card",
          status: "GENERATED",
          summary: session.summary ?? null,
          energy_theme: session.energyTheme ?? null,
          zodiac_note: session.zodiacNote ?? null,
          created_at: session.createdAt ?? new Date().toISOString(),
        },
        { onConflict: "id", ignoreDuplicates: false }
      );

    if (sessionErr) {
      console.error("tarot-create-reading: session upsert error", sessionErr);
      return {
        statusCode: 500,
        body: JSON.stringify({ error: "Failed to persist reading session" }),
      };
    }

    // Upsert card results (position is the unique key within a session)
    const cardRows = session.cards.map((drawn) => ({
      session_id: session.id,
      card_id: drawn.card.id,
      card_name: drawn.card.name,
      card_arcana: drawn.card.arcana,
      card_suit: drawn.card.suit ?? null,
      position: drawn.position.index,
      position_label: drawn.position.label,
      is_reversed: drawn.isReversed,
      interpretation: drawn.interpretation,
    }));

    const { error: cardsErr } = await supabase
      .from("reading_card_results")
      .upsert(cardRows, { onConflict: "session_id,position", ignoreDuplicates: true });

    if (cardsErr) {
      console.error("tarot-create-reading: card results upsert error", cardsErr);
      // Non-fatal — session is persisted; log and continue
    }

    // Persist product recommendations
    if (recommendations.length > 0) {
      const recRows = recommendations.map((rec, idx) => ({
        session_id: session.id,
        offer_id: rec.offerId,
        reason: rec.reason ?? null,
        score: rec.score ?? 1.0,
        position: idx,
      }));

      const { error: recErr } = await supabase
        .from("tarot_product_recommendations")
        .upsert(recRows, { onConflict: "session_id,offer_id", ignoreDuplicates: true });

      if (recErr) {
        console.error("tarot-create-reading: recommendations upsert error", recErr);
      }
    }

    return {
      statusCode: 200,
      body: JSON.stringify({ sessionId: session.id, status: "GENERATED" }),
    };
  } catch (err) {
    console.error("tarot-create-reading: unhandled error", err);
    return {
      statusCode: 500,
      body: JSON.stringify({ error: "Internal server error" }),
    };
  }
}
